noncompliant:
// Using single L for values that don't fit in long
auto large_value = 9223372036854775808L; // Noncompliant: value too large for long, becomes long long

// Ambiguous suffix
auto value1 = 1000000L; // Noncompliant: unclear if long or long long intended
auto value2 = 0x1FFFFFFFFL; // Noncompliant: may not fit in long on some systems

compliant:
// Use LL for long long values
auto large_value = 9223372036854775808LL; // Compliant: explicitly long long

// Use L only for values that definitely fit in long
auto small_value = 1000L; // Compliant: clearly fits in long

// Use appropriate suffixes
auto int_value = 42;        // Compliant: int literal
auto long_value = 42L;      // Compliant: long literal
auto longlong_value = 42LL; // Compliant: long long literal
auto unsigned_value = 42U;  // Compliant: unsigned literal
auto ul_value = 42UL;       // Compliant: unsigned long literal
